      <div className="flex justify-end gap-2 pt-2">
        <Button
          variant="outline"
          className="border-white/15 bg-transparent text-white hover:bg-white/10"
          onClick={onCancel}
        >
          Cancel
        </Button>
        <Button
          className="bg-white text-black hover:bg-white/90"
          onClick={() => onSave(v)}
        >
          Save endpoint
        </Button>
      </div>
    </div>
  );
}

