import { createFileRoute, useNavigate } from "@tanstack/react-router";
import { useEffect } from "react";
import { Cockpit } from "./index";
import { store, useStore } from "@/lib/cockpit-store";

export const Route = createFileRoute("/thread/$id")({
  head: ({ params }) => ({
    meta: [
      { title: `Thread ${params.id.slice(0, 8)} — Cockpit` },
      { name: "description", content: "Continue a saved conversation." },
    ],
  }),
  component: ThreadPage,
});

function ThreadPage() {
  const { id } = Route.useParams();
  const threads = useStore((s) => s.threads);
  const exists = threads.some((t) => t.id === id);
  const navigate = useNavigate();

  useEffect(() => {
    if (exists) store.selectThread(id);
  }, [id, exists]);

  useEffect(() => {
    if (!exists && threads.length >= 0) {
      // thread vanished — bounce to home
      const t = setTimeout(() => navigate({ to: "/" }), 800);
      return () => clearTimeout(t);
    }
  }, [exists, threads.length, navigate]);

  if (!exists) {
    return (
      <div className="grid min-h-[100dvh] place-items-center bg-black text-white/70">
        <p className="text-sm">Thread not found — returning home…</p>
      </div>
    );
  }
  return <Cockpit />;
}

import { useSyncExternalStore } from "react";

export type EndpointLabel = {
  id: string;
  label: string;
  path: string; // e.g. /v1/chat/completions
  method: "GET" | "POST";
  cacheTtlSec: number; // 0 = no cache
  bodyTemplate?: string; // JSON template, {{messages}} {{model}} {{prompt}}
  headers?: string; // JSON string
  responsePath?: string; // dot path to text e.g. choices.0.message.content
  stream?: boolean;
  pinned?: boolean;
};

export type Settings = {
  userName: string;
  baseUrl: string;
  apiKey: string;
  model: string;
  defaultEndpointId: string;
  endpoints: EndpointLabel[];
};

export type Message = {
  id: string;
  role: "user" | "assistant" | "system";
  content: string;
  endpointLabel?: string;
  endpointUsed?: string;
  cached?: boolean;
  error?: boolean;
  pending?: boolean;
  timestamp?: number;
  ts: number;
  attachments?: string[]; // data URLs
};

export type Thread = {
  id: string;
  title: string;
  messages: Message[];
  updatedAt: number;
  temporary?: boolean;
};

const SETTINGS_KEY = "***";
const THREADS_KEY = "***";
const CACHE_KEY = "***";
const STATS_KEY = "***";

export type EndpointStat = { hits: number; misses: number };
type StatsMap = Record<string, EndpointStat>;

function loadStats(): StatsMap {
  if (typeof window === "undefined") return {};
  try {
    return JSON.parse(localStorage.getItem(STATS_KEY) || "{}");
  } catch {
    return {};
  }
}
function saveStats(s: StatsMap) {
  if (typeof window === "undefined") return;
  localStorage.setItem(STATS_KEY, JSON.stringify(s));
}
export function getEndpointStats(): StatsMap {
  return loadStats();
}
export function bumpEndpointStat(id: string, kind: "hit" | "miss") {
  const s = loadStats();
  const cur = s[id] ?? { hits: 0, misses: 0 };
  if (kind === "hit") cur.hits++;
  else cur.misses++;
  s[id] = cur;
  saveStats(s);
  statsListeners.forEach((l) => l());
}
export function resetEndpointStats() {
  saveStats({});
  statsListeners.forEach((l) => l());
}
const statsListeners = new Set<() => void>();
export function subscribeEndpointStats(l: () => void) {
  statsListeners.add(l);
  return () => statsListeners.delete(l);
}

